                    for path in paths {
                        if path.is_file() {
                            let _ = tx.send(path);
                        }
                    }
                }
            }
            Err(e) => eprintln!("Watch error: {:?}", e),
        }
    }

    Ok(())
}

fn organize_file(file_path: &Path) {
    if let Some(extension) = file_path.extension() {
        let ext_str = extension.to_string_lossy().to_lowercase();

        if let Some(parent_dir) = file_path.parent() {
            let target_dir = parent_dir.join(&ext_str);

            // Create extension directory if it doesn't exist
            if !target_dir.exists() {
                if let Err(e) = fs::create_dir_all(&target_dir) {
                    eprintln!("Failed to create directory for extension {}: {}", ext_str, e);
                    return;
                }
            }

            if let Some(file_name) = file_path.file_name() {
                let target_path = target_dir.join(file_name);

                // Move the file
                match fs::rename(file_path, &target_path) {
                    Ok(_) => println!("Moved {:?} to {:?}", file_path, target_path),
                    Err(e) => eprintln!("Failed to move {:?}: {}", file_path, e),
                }
            }
        }
    }
}
