    private List<String> headers;
    private List<List<String>> records;
    private static final int BATCH_SIZE = 10000;

    public CSVProcessor(File csvFile, File configFile, char delimiter, boolean hasHeader) {
        this.csvFile = csvFile;
        this.configFile = configFile;
        this.delimiter = delimiter;
        this.hasHeader = hasHeader;
    }

    public void process() throws IOException {
        System.out.println("Reading CSV file...");
        readCSV();

        System.out.println("Checking data consistency...");
        checkDataConsistency();

        System.out.println("Removing duplicates...");
        removeDuplicates();

        System.out.println("Reordering columns based on configuration...");
        reorderColumns();

        System.out.println("Writing processed data to file...");
        writeProcessedCSV();

        System.out.println("Processing completed successfully!");
    }

    private void readCSV() throws IOException {
        records = new ArrayList<>();

        try (BufferedReader reader = Files.newBufferedReader(csvFile.toPath(), StandardCharsets.UTF_8)) {
            String line;

            // Process header if present
            if (hasHeader && (line = reader.readLine()) != null) {
                headers = parseCSVLine(line);
            }

            // Process data rows
            while ((line = reader.readLine()) != null) {
                records.add(parseCSVLine(line));
            }
        }
    }

    private List<String> parseCSVLine(String line) {
        List<String> values = new ArrayList<>();
        StringBuilder currentValue = new StringBuilder();
        boolean inQuotes = false;

        for (int i = 0; i < line.length(); i++) {
            char c = line.charAt(i);

            if (c == '"') {
                inQuotes = !inQuotes;
            } else if (c == delimiter && !inQuotes) {
                values.add(currentValue.toString());
                currentValue = new StringBuilder();
            } else {
                currentValue.append(c);
            }
        }

        values.add(currentValue.toString());
        return values;
    }

    private void checkDataConsistency() {
        if (headers == null || records.isEmpty()) {
            return;
        }

        int expectedColumnCount = headers.size();
        List<Integer> inconsistentRows = new ArrayList<>();

        var rowIndex = new AtomicInteger(0);
        records.forEach((var record) -> {
            if (record.size() != expectedColumnCount) {
                inconsistentRows.add(rowIndex.get());
            }
            rowIndex.incrementAndGet();
        });

        if (!inconsistentRows.isEmpty()) {
            System.out.println("WARNING: Found " + inconsistentRows.size() + 
                    " rows with inconsistent column counts");
            System.out.println("First 10 inconsistent rows: " + 
                    inconsistentRows.stream().limit(10).map(String::valueOf).collect(Collectors.joining(", ")));
        }
    }

    private void removeDuplicates() {
        int originalSize = records.size();
        Set<List<String>> uniqueRecords = new LinkedHashSet<>(records);
        records = new ArrayList<>(uniqueRecords);

        int duplicatesRemoved = originalSize - records.size();
        if (duplicatesRemoved > 0) {
            System.out.println("Removed " + duplicatesRemoved + " duplicate records");
        }
    }

    private void reorderColumns() throws IOException {
        if (headers == null || configFile == null || !configFile.exists()) {
            return;
        }

        // Read column order from config
        List<String> columnOrder = Files.readAllLines(configFile.toPath());
        Map<String, Integer> headerToIndexMap = new HashMap<>();

        // Check if all headers from config exist in the CSV
        boolean validConfig = true;
        for (String column : columnOrder) {
            if (!headers.contains(column)) {
                System.out.println("WARNING: Column '" + column + "' from config not found in CSV");
                validConfig = false;
            }
        }

        if (!validConfig || columnOrder.isEmpty()) {
            System.out.println("Column reordering skipped due to invalid configuration");
            return;
        }

        // Create mapping of original header positions
        for (int i = 0; i < headers.size(); i++) {
            headerToIndexMap.put(headers.get(i), i);
        }

        // Reorder headers
        List<String> newHeaders = new ArrayList<>(columnOrder);

        // Add any headers not specified in config at the end
        headers.stream()
               .filter(Predicate.not(columnOrder::contains))
               .forEach(newHeaders::add);

        // Reorder data
        List<List<String>> reorderedRecords = new ArrayList<>();

        for (var record : records) {
            List<String> newRecord = new ArrayList<>();
            for (String header : newHeaders) {
                int index = headerToIndexMap.get(header);
                newRecord.add(index < record.size() ? record.get(index) : "");
            }
            reorderedRecords.add(newRecord);
        }

        headers = newHeaders;
        records = reorderedRecords;
    }

    private void writeProcessedCSV() throws IOException {
        String outputName = csvFile.getName().replaceFirst("\\.csv$", "_processed.csv");
        Path outputPath = csvFile.toPath().getParent().resolve(outputName);

        try (BufferedWriter writer = Files.newBufferedWriter(outputPath, StandardCharsets.UTF_8)) {
            // Write header
            if (headers != null) {
                writer.write(String.join(String.valueOf(delimiter), headers));
                writer.newLine();
            }

            // Write data in batches
            for (int i = 0; i < records.size(); i += BATCH_SIZE) {
                int end = Math.min(i + BATCH_SIZE, records.size());
                for (int j = i; j < end; j++) {
                    writer.write(String.join(String.valueOf(delimiter), records.get(j)));
                    writer.newLine();
                }
            }
        }

        System.out.println("Processed file saved to: " + outputPath);
    }

    public static void main(String[] args) {
        if (args.length < 2) {
            System.out.println("Usage: java CSVProcessor <csvFile> <configFile> [delimiter] [hasHeader]");
            System.out.println("  csvFile: Path to the CSV file to process");
            System.out.println("  configFile: Path to the column configuration file");
            System.out.println("  delimiter: CSV delimiter character (default: ,)");
            System.out.println("  hasHeader: true if CSV has header row (default: true)");
            return;
        }

        File csvFile = new File(args[0]);
        File configFile = new File(args[1]);
        char delimiter = args.length > 2 ? args[2].charAt(0) : ',';
        boolean hasHeader = args.length > 3 ? Boolean.parseBoolean(args[3]) : true;

        try {
            CSVProcessor processor = new CSVProcessor(csvFile, configFile, delimiter, hasHeader);
            processor.process();
        } catch (IOException e) {
            System.err.println("Error processing CSV file: " + e.getMessage());
            e.printStackTrace();
        }
    }
}
