                System.err.println("Error reading log file: " + e.getMessage());
                throw e;
            }
        }
    }

    private String readFileFromPosition(long position) throws IOException {
        byte[] bytes = Files.readAllBytes(logFilePath);
        return new String(bytes, (int) position, (int) (bytes.length - position));
