package com.library.repository;

import com.library.model.Book;
import com.library.model.Journal;
import com.library.model.Magazine;
import com.library.model.Media;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.jdbc.core.JdbcTemplate;
import org.springframework.jdbc.core.RowMapper;
import org.springframework.jdbc.support.GeneratedKeyHolder;
import org.springframework.jdbc.support.KeyHolder;
import org.springframework.stereotype.Repository;
import org.springframework.transaction.annotation.Transactional;

import java.sql.PreparedStatement;
import java.sql.Statement;
import java.sql.Types;
import java.time.LocalDate;
import java.util.List;
import java.util.Optional;
import java.util.concurrent.CompletableFuture;

@Repository
public class MediaRepository {

    private final JdbcTemplate jdbcTemplate;

    @Autowired
    public MediaRepository(JdbcTemplate jdbcTemplate) {
        this.jdbcTemplate = jdbcTemplate;
        initTables();
    }

    private void initTables() {
        jdbcTemplate.execute("""
            CREATE TABLE IF NOT EXISTS media (
                id BIGINT AUTO_INCREMENT PRIMARY KEY,
                media_type VARCHAR(10) NOT NULL,
                title VARCHAR(255) NOT NULL,
                publisher VARCHAR(255),
                publish_date DATE,
                isbn VARCHAR(20)
            )
        """);

        jdbcTemplate.execute("""
            CREATE TABLE IF NOT EXISTS book (
                id BIGINT PRIMARY KEY,
                author VARCHAR(255),
                page_count INT,
                FOREIGN KEY (id) REFERENCES media(id) ON DELETE CASCADE
            )
        """);

        jdbcTemplate.execute("""
            CREATE TABLE IF NOT EXISTS book_genres (
                book_id BIGINT,
                genre VARCHAR(100),
                PRIMARY KEY (book_id, genre),
                FOREIGN KEY (book_id) REFERENCES book(id) ON DELETE CASCADE
            )
        """);

        jdbcTemplate.execute("""
            CREATE TABLE IF NOT EXISTS journal (
                id BIGINT PRIMARY KEY,
                volume INT,
                issue INT,
                peer_reviewed BOOLEAN,
                FOREIGN KEY (id) REFERENCES media(id) ON DELETE CASCADE
            )
        """);

        jdbcTemplate.execute("""
            CREATE TABLE IF NOT EXISTS journal_subjects (
                journal_id BIGINT,
                subject VARCHAR(100),
                PRIMARY KEY (journal_id, subject),
                FOREIGN KEY (journal_id) REFERENCES journal(id) ON DELETE CASCADE
            )
        """);

        jdbcTemplate.execute("""
            CREATE TABLE IF NOT EXISTS magazine (
                id BIGINT PRIMARY KEY,
                issue INT,
                frequency VARCHAR(50),
                FOREIGN KEY (id) REFERENCES media(id) ON DELETE CASCADE
            )
        """);

        jdbcTemplate.execute("""
            CREATE TABLE IF NOT EXISTS magazine_categories (
                magazine_id BIGINT,
                category VARCHAR(100),
                PRIMARY KEY (magazine_id, category),
                FOREIGN KEY (magazine_id) REFERENCES magazine(id) ON DELETE CASCADE
            )
        """);
    }

    @Transactional
    public CompletableFuture<Media> save(Media media) {
        return CompletableFuture.supplyAsync(() -> {
            KeyHolder keyHolder = new GeneratedKeyHolder();

            jdbcTemplate.update(connection -> {
                PreparedStatement ps = connection.prepareStatement(
                    "INSERT INTO media (media_type, title, publisher, publish_date, isbn) VALUES (?, ?, ?, ?, ?)",
                    Statement.RETURN_GENERATED_KEYS
                );
                ps.setString(1, media.getMediaType());
                ps.setString(2, media.getTitle());
                ps.setString(3, media.getPublisher());
                ps.setObject(4, media.getPublishDate());
                ps.setString(5, media.getIsbn());
                return ps;
            }, keyHolder);

            Long id = keyHolder.getKey().longValue();
            media.setId(id);

            switch (media) {
                case Book book -> saveBook(book);
                case Journal journal -> saveJournal(journal);
                case Magazine magazine -> saveMagazine(magazine);
                default -> throw new IllegalArgumentException("Unknown media type");
            }

            return media;
        });
    }

    private void saveBook(Book book) {
        jdbcTemplate.update(
            "INSERT INTO book (id, author, page_count) VALUES (?, ?, ?)",
            book.getId(), book.getAuthor(), book.getPageCount()
        );

        if (book.getGenres() != null) {
            for (String genre : book.getGenres()) {
                jdbcTemplate.update(
                    "INSERT INTO book_genres (book_id, genre) VALUES (?, ?)",
                    book.getId(), genre
                );
            }
        }
    }

    private void saveJournal(Journal journal) {
        jdbcTemplate.update(
            "INSERT INTO journal (id, volume, issue, peer_reviewed) VALUES (?, ?, ?, ?)",
            journal.getId(), journal.getVolume(), journal.getIssue(), journal.isPeerReviewed()
        );

        if (journal.getSubjects() != null) {
            for (String subject : journal.getSubjects()) {
                jdbcTemplate.update(
                    "INSERT INTO journal_subjects (journal_id, subject) VALUES (?, ?)",
                    journal.getId(), subject
                );
            }
        }
    }

    private void saveMagazine(Magazine magazine) {
        jdbcTemplate.update(
            "INSERT INTO magazine (id, issue, frequency) VALUES (?, ?, ?)",
            magazine.getId(), magazine.getIssue(), magazine.getFrequency()
        );

        if (magazine.getCategories() != null) {
            for (String category : magazine.getCategories()) {
                jdbcTemplate.update(
                    "INSERT INTO magazine_categories (magazine_id, category) VALUES (?, ?)",
                    magazine.getId(), category
                );
            }
        }
    }

    @Transactional(readOnly = true)
    public CompletableFuture<List<Media>> findAll() {
        return CompletableFuture.supplyAsync(() -> 
            jdbcTemplate.query(
                "SELECT id, media_type FROM media",
                (rs, rowNum) -> {
                    Long id = rs.getLong("id");
                    String mediaType = rs.getString("media_type");

                    return switch (mediaType) {
                        case "BOOK" -> findBookById(id).orElse(null);
                        case "JOURNAL" -> findJournalById(id).orElse(null);
                        case "MAGAZINE" -> findMagazineById(id).orElse(null);
                        default -> null;
                    };
                }
            ).stream().filter(media -> media != null).toList()
        );
    }

    @Transactional(readOnly = true)
    public CompletableFuture<Optional<Media>> findById(Long id) {
        return CompletableFuture.supplyAsync(() -> {
            String mediaType = jdbcTemplate.queryForObject(
                "SELECT media_type FROM media WHERE id = ?",
                String.class,
                id
            );

            if (mediaType == null) {
                return Optional.empty();
            }

            return switch (mediaType) {
                case "BOOK" -> findBookById(id);
                case "JOURNAL" -> findJournalById(id);
                case "MAGAZINE" -> findMagazineById(id);
                default -> Optional.empty();
            };
        });
    }

    private Optional<Media> findBookById(Long id) {
        return jdbcTemplate.query(
            """
            SELECT m.id, m.title, m.publisher, m.publish_date, m.isbn, 
                   b.author, b.page_count
            FROM media m
            JOIN book b ON m.id = b.id
            WHERE m.id = ?
            """,
            new Object[]{id},
            (rs, rowNum) -> {
                Book book = new Book();
                book.setId(rs.getLong("id"));
                book.setTitle(rs.getString("title"));
                book.setPublisher(rs.getString("publisher"));
                book.setPublishDate(rs.getObject("publish_date", LocalDate.class));
                book.setIsbn(rs.getString("isbn"));
                book.setAuthor(rs.getString("author"));
                book.setPageCount(rs.getInt("page_count"));

                List<String> genres = jdbcTemplate.queryForList(
                    "SELECT genre FROM book_genres WHERE book_id = ?",
                    String.class,
                    id
                );
                book.setGenres(genres);

                return book;
            }
        ).stream().findFirst();
    }

    private Optional<Media> findJournalById(Long id) {
        return jdbcTemplate.query(
            """
            SELECT m.id, m.title, m.publisher, m.publish_date, m.isbn, 
                   j.volume, j.issue, j.peer_reviewed
            FROM media m
            JOIN journal j ON m.id = j.id
            WHERE m.id = ?
            """,
            new Object[]{id},
            (rs, rowNum) -> {
                Journal journal = new Journal();
                journal.setId(rs.getLong("id"));
                journal.setTitle(rs.getString("title"));
                journal.setPublisher(rs.getString("publisher"));
                journal.setPublishDate(rs.getObject("publish_date", LocalDate.class));
                journal.setIsbn(rs.getString("isbn"));
                journal.setVolume(rs.getInt("volume"));
                journal.setIssue(rs.getInt("issue"));
                journal.setPeerReviewed(rs.getBoolean("peer_reviewed"));

                List<String> subjects = jdbcTemplate.queryForList(
                    "SELECT subject FROM journal_subjects WHERE journal_id = ?",
                    String.class,
                    id
                );
                journal.setSubjects(subjects);

                return journal;
            }
        ).stream().findFirst();
    }

    private Optional<Media> findMagazineById(Long id) {
        return jdbcTemplate.query(
            """
            SELECT m.id, m.title, m.publisher, m.publish_date, m.isbn, 
                   mg.issue, mg.frequency
            FROM media m
            JOIN magazine mg ON m.id = mg.id
            WHERE m.id = ?
            """,
            new Object[]{id},
            (rs, rowNum) -> {
                Magazine magazine = new Magazine();
                magazine.setId(rs.getLong("id"));
                magazine.setTitle(rs.getString("title"));
                magazine.setPublisher(rs.getString("publisher"));
                magazine.setPublishDate(rs.getObject("publish_date", LocalDate.class));
                magazine.setIsbn(rs.getString("isbn"));
                magazine.setIssue(rs.getInt("issue"));
                magazine.setFrequency(rs.getString("frequency"));

                List<String> categories = jdbcTemplate.queryForList(
                    "SELECT category FROM magazine_categories WHERE magazine_id = ?",
                    String.class,
                    id
                );
                magazine.setCategories(categories);

                return magazine;
            }
        ).stream().findFirst();
    }

    @Transactional
    public CompletableFuture<Boolean> update(Media media) {
        return CompletableFuture.supplyAsync(() -> {
            int updated = jdbcTemplate.update(
                "UPDATE media SET title = ?, publisher = ?, publish_date = ?, isbn = ? WHERE id = ?",
                media.getTitle(), media.getPublisher(), media.getPublishDate(), media.getIsbn(), media.getId()
            );

            if (updated == 0) {
                return false;
            }

            switch (media) {
                case Book book -> updateBook(book);
                case Journal journal -> updateJournal(journal);
                case Magazine magazine -> updateMagazine(magazine);
                default -> throw new IllegalArgumentException("Unknown media type");
            }

            return true;
        });
    }

    private void updateBook(Book book) {
        jdbcTemplate.update(
            "UPDATE book SET author = ?, page_count = ? WHERE id = ?",
            book.getAuthor(), book.getPageCount(), book.getId()
        );

        jdbcTemplate.update("DELETE FROM book_genres WHERE book_id = ?", book.getId());
        if (book.getGenres() != null) {
            for (String genre : book.getGenres()) {
                jdbcTemplate.update(
                    "INSERT INTO book_genres (book_id, genre) VALUES (?, ?)",
                    book.getId(), genre
                );
            }
        }
    }

    private void updateJournal(Journal journal) {
        jdbcTemplate.update(
            "UPDATE journal SET volume = ?, issue = ?, peer_reviewed = ? WHERE id = ?",
            journal.getVolume(), journal.getIssue(), journal.isPeerReviewed(), journal.getId()
        );

        jdbcTemplate.update("DELETE FROM journal_subjects WHERE journal_id = ?", journal.getId());
        if (journal.getSubjects() != null) {
            for (String subject : journal.getSubjects()) {
                jdbcTemplate.update(
                    "INSERT INTO journal_subjects (journal_id, subject) VALUES (?, ?)",
                    journal.getId(), subject
                );
            }
        }
    }

    private void updateMagazine(Magazine magazine) {
        jdbcTemplate.update(
            "UPDATE magazine SET issue = ?, frequency = ? WHERE id = ?",
            magazine.getIssue(), magazine.getFrequency(), magazine.getId()
        );

        jdbcTemplate.update("DELETE FROM magazine_categories WHERE magazine_id = ?", magazine.getId());
        if (magazine.getCategories() != null) {
            for (String category : magazine.getCategories()) {
                jdbcTemplate.update(
                    "INSERT INTO magazine_categories (magazine_id, category) VALUES (?, ?)",
                    magazine.getId(), category
                );
            }
        }
    }

    @Transactional
    public CompletableFuture<Boolean> deleteById(Long id) {
        return CompletableFuture.supplyAsync(() -> {
            int deleted = jdbcTemplate.update("DELETE FROM media WHERE id = ?", id);
            return deleted > 0;
        });
    }
