package com.library.controller;

import com.library.model.Book;
import com.library.model.Journal;
import com.library.model.Magazine;
import com.library.model.Media;
import com.library.service.MediaService;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.context.request.async.DeferredResult;

import java.util.List;
import java.util.Map;
import java.util.concurrent.CompletableFuture;

@RestController
@RequestMapping("/api/media")
public class MediaController {

    private final MediaService mediaService;

    @Autowired
    public MediaController(MediaService mediaService) {
        this.mediaService = mediaService;
    }

    @PostMapping
    public DeferredResult<ResponseEntity<Media>> createMedia(@RequestBody Map<String, Object> mediaData) {
        DeferredResult<ResponseEntity<Media>> result = new DeferredResult<>();

        String mediaType = (String) mediaData.get("mediaType");
        Media media = switch(mediaType) {
            case "BOOK" -> createBookFromMap(mediaData);
            case "JOURNAL" -> createJournalFromMap(mediaData);
            case "MAGAZINE" -> createMagazineFromMap(mediaData);
            default -> throw new IllegalArgumentException("Invalid media type: " + mediaType);
        };

        mediaService.createMedia(media)
            .thenAccept(savedMedia -> 
                result.setResult(new ResponseEntity<>(savedMedia, HttpStatus.CREATED)))
            .exceptionally(ex -> {
                result.setErrorResult(
                    ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                        .body("Error creating media: " + ex.getMessage())
                );
                return null;
            });

        return result;
    }

    @GetMapping
    public DeferredResult<ResponseEntity<List<Media>>> getAllMedia() {
        DeferredResult<ResponseEntity<List<Media>>> result = new DeferredResult<>();

        mediaService.getAllMedia()
            .thenAccept(mediaList -> 
                result.setResult(ResponseEntity.ok(mediaList)))
            .exceptionally(ex -> {
                result.setErrorResult(
                    ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                        .body("Error retrieving media: " + ex.getMessage())
                );
                return null;
            });

        return result;
    }

    @GetMapping("/{id}")
    public DeferredResult<ResponseEntity<?>> getMediaById(@PathVariable Long id) {
        DeferredResult<ResponseEntity<?>> result = new DeferredResult<>();

        mediaService.getMediaById(id)
            .thenAccept(mediaOpt -> {
                if (mediaOpt.isPresent()) {
                    result.setResult(ResponseEntity.ok(mediaOpt.get()));
                } else {
                    result.setResult(ResponseEntity.notFound().build());
                }
            })
            .exceptionally(ex -> {
                result.setErrorResult(
                    ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                        .body("Error retrieving media: " + ex.getMessage())
                );
                return null;
            });

        return result;
    }

    @PutMapping("/{id}")
    public DeferredResult<ResponseEntity<?>> updateMedia(
            @PathVariable Long id, 
            @RequestBody Map<String, Object> mediaData) {

        DeferredResult<ResponseEntity<?>> result = new DeferredResult<>();

        String mediaType = (String) mediaData.get("mediaType");
        Media media = switch(mediaType) {
            case "BOOK" -> createBookFromMap(mediaData);
            case "JOURNAL" -> createJournalFromMap(mediaData);
            case "MAGAZINE" -> createMagazineFromMap(mediaData);
            default -> throw new IllegalArgumentException("Invalid media type: " + mediaType);
        };

        mediaService.updateMedia(id, media)
            .thenAccept(updated -> {
                if (updated) {
                    result.setResult(ResponseEntity.ok().build());
                } else {
                    result.setResult(ResponseEntity.notFound().build());
                }
            })
            .exceptionally(ex -> {
                result.setErrorResult(
                    ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                        .body("Error updating media: " + ex.getMessage())
                );
                return null;
            });

        return result;
    }

    @DeleteMapping("/{id}")
    public DeferredResult<ResponseEntity<?>> deleteMedia(@PathVariable Long id) {
        DeferredResult<ResponseEntity<?>> result = new DeferredResult<>();

        mediaService.deleteMedia(id)
            .thenAccept(deleted -> {
                if (deleted) {
                    result.setResult(ResponseEntity.noContent().build());
                } else {
                    result.setResult(ResponseEntity.notFound().build());
                }
            })
            .exceptionally(ex -> {
                result.setErrorResult(
                    ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                        .body("Error deleting media: " + ex.getMessage())
                );
                return null;
            });

        return result;
    }

    @SuppressWarnings("unchecked")
    private Book createBookFromMap(Map<String, Object> data) {
        Book book = new Book();
        setBaseMediaProperties(book, data);
        book.setAuthor((String) data.get("author"));
        book.setPageCount((Integer) data.get("pageCount"));
        book.setGenres((List<String>) data.get("genres"));
        return book;
    }

    @SuppressWarnings("unchecked")
    private Journal createJournalFromMap(Map<String, Object> data) {
        Journal journal = new Journal();
        setBaseMediaProperties(journal, data);
        journal.setVolume((Integer) data.get("volume"));
        journal.setIssue((Integer) data.get("issue"));
        journal.setSubjects((List<String>) data.get("subjects"));
        journal.setPeerReviewed((Boolean) data.get("peerReviewed"));
        return journal;
    }

    @SuppressWarnings("unchecked")
    private Magazine createMagazineFromMap(Map<String, Object> data) {
        Magazine magazine = new Magazine();
        setBaseMediaProperties(magazine, data);
        magazine.setIssue((Integer) data.get("issue"));
        magazine.setFrequency((String) data.get("frequency"));
        magazine.setCategories((List<String>) data.get("categories"));
        return magazine;
    }

    private void setBaseMediaProperties(Media media, Map<String, Object> data) {
        if (data.containsKey("id")) {
            media.setId(Long.valueOf(data.get("id").toString()));
        }
        media.setTitle((String) data.get("title"));
        media.setPublisher((String) data.get("publisher"));

        if (data.containsKey("publishDate")) {
            String dateString = (String) data.get("publishDate");
            media.setPublishDate(java.time.LocalDate.parse(dateString));
        }

        media.setIsbn((String) data.get("isbn"));
    }
}
