        self.mongo_handler = mongo_handler
        self.processed_files = {}

    def on_created(self, event: FileCreatedEvent) -> None:
        if event.is_directory or not event.src_path.endswith(".json"):
            return
        self._process_file(event.src_path)

    def on_modified(self, event: FileModifiedEvent) -> None:
        if event.is_directory or not event.src_path.endswith(".json"):
            return
        self._process_file(event.src_path)

    def _process_file(self, file_path: str) -> None:
        try:
            # Check if file was recently processed (to avoid duplicate processing)
            file_stat = os.stat(file_path)
            last_modified = file_stat.st_mtime

            if file_path in self.processed_files and self.processed_files[file_path] == last_modified:
                return

            self.processed_files[file_path] = last_modified
            logger.info(f"Processing file: {file_path}")

            with open(file_path, 'r') as f:
                json_data = json.load(f)

            # Validate JSON structure using Python 3.13 pattern matching
            match json_data:
                case {"id": str(id), "name": str(name), "timestamp": str(timestamp), 
                      "data": dict(data), "tags": list(tags), **rest} if self._validate_json(json_data):
                    logger.info(f"Valid JSON structure found in {file_path}")
                    self.mongo_handler.update_document(json_data)
                case _:
                    logger.error(f"Invalid JSON structure in {file_path}")

        except json.JSONDecodeError as e:
            logger.error(f"JSON parsing error in {file_path}: {e}")
        except Exception as e:
            logger.error(f"Error processing file {file_path}: {e}")

    def _validate_json(self, data: Dict[str, Any]) -> bool:
        try:
            # Additional validation beyond structure
            if not data["id"] or not isinstance(data["id"], str):
                return False

            # Validate timestamp format
            try:
                datetime.fromisoformat(data["timestamp"])
            except ValueError:
                return False

            # Check if tags are all strings
            if not all(isinstance(tag, str) for tag in data["tags"]):
                return False

            return True
        except Exception as e:
            logger.error(f"Validation error: {e}")
            return False

