package com.rssprocessor.processor;

import com.rssprocessor.model.Feed;
import com.rssprocessor.model.FeedItem;
import com.rssprocessor.model.ParseResult;

import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.InputStream;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.time.format.DateTimeParseException;
import java.util.ArrayList;
import java.util.List;
import java.util.Locale;

import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

public class FeedProcessor {
    private static final HttpClient httpClient = HttpClient.newHttpClient();
    private static final DateTimeFormatter RFC_2822_FORMATTER = 
            DateTimeFormatter.ofPattern("EEE, dd MMM yyyy HH:mm:ss Z", Locale.ENGLISH);

    public static Feed fetchAndParseFeed(String feedUrl) throws Exception {
        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(feedUrl))
                .GET()
                .build();

        HttpResponse<InputStream> response = httpClient.send(request, 
                HttpResponse.BodyHandlers.ofInputStream());

        if (response.statusCode() != 200) {
            throw new RuntimeException("HTTP " + response.statusCode() + " for " + feedUrl);
        }

        ParseResult result = parseXmlFeed(response.body());

        return switch (result) {
            case ParseResult.Success success -> success.feed();
            case ParseResult.Failure failure -> throw new RuntimeException("Parse error: " + failure.error());
        };
    }

    private static ParseResult parseXmlFeed(InputStream inputStream) {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            DocumentBuilder builder = factory.newDocumentBuilder();
            Document document = builder.parse(inputStream);

            Element root = document.getDocumentElement();
            String rootName = root.getNodeName();

            return switch (rootName) {
                case "rss" -> parseRSSFeed(document);
                case "feed" -> parseAtomFeed(document);
                default -> new ParseResult.Failure("Unsupported feed format: " + rootName);
            };

        } catch (Exception e) {
            return new ParseResult.Failure("XML parsing error: " + e.getMessage());
        }
    }

    private static ParseResult parseRSSFeed(Document document) {
        try {
            Element channel = (Element) document.getElementsByTagName("channel").item(0);
            String title = getTextContent(channel, "title");
            String description = getTextContent(channel, "description");

            NodeList items = channel.getElementsByTagName("item");
            List<FeedItem> feedItems = new ArrayList<>();

            for (int i = 0; i < items.getLength(); i++) {
                Element item = (Element) items.item(i);
                String itemTitle = getTextContent(item, "title");
                String link = getTextContent(item, "link");
                String itemDescription = getTextContent(item, "description");
                String pubDateStr = getTextContent(item, "pubDate");

                LocalDateTime pubDate = parseDate(pubDateStr);
                feedItems.add(new FeedItem(itemTitle, link, itemDescription, pubDate));
            }

            return new ParseResult.Success(new Feed(title, description, feedItems));
        } catch (Exception e) {
            return new ParseResult.Failure("RSS parsing error: " + e.getMessage());
        }
    }

    private static ParseResult parseAtomFeed(Document document) {
        try {
            Element feed = document.getDocumentElement();
            String title = getTextContent(feed, "title");
            String description = getTextContent(feed, "subtitle");

            NodeList entries = feed.getElementsByTagName("entry");
            List<FeedItem> feedItems = new ArrayList<>();

            for (int i = 0; i < entries.getLength(); i++) {
                Element entry = (Element) entries.item(i);
                String itemTitle = getTextContent(entry, "title");
                String link = getLinkHref(entry);
                String itemDescription = getTextContent(entry, "summary");
                String pubDateStr = getTextContent(entry, "published");

                LocalDateTime pubDate = parseDate(pubDateStr);
                feedItems.add(new FeedItem(itemTitle, link, itemDescription, pubDate));
            }

            return new ParseResult.Success(new Feed(title, description, feedItems));
        } catch (Exception e) {
            return new ParseResult.Failure("Atom parsing error: " + e.getMessage());
        }
    }

    private static String getTextContent(Element parent, String tagName) {
        NodeList nodeList = parent.getElementsByTagName(tagName);
        if (nodeList.getLength() > 0) {
            return nodeList.item(0).getTextContent().trim();
        }
        return "";
    }

    private static String getLinkHref(Element entry) {
        NodeList links = entry.getElementsByTagName("link");
        for (int i = 0; i < links.getLength(); i++) {
            Element link = (Element) links.item(i);
            if ("alternate".equals(link.getAttribute("rel")) || link.getAttribute("rel").isEmpty()) {
                return link.getAttribute("href");
            }
        }
        return "";
    }

    private static LocalDateTime parseDate(String dateStr) {
        if (dateStr == null || dateStr.isEmpty()) {
            return LocalDateTime.now();
        }

        try {
            return LocalDateTime.parse(dateStr, RFC_2822_FORMATTER);
        } catch (DateTimeParseException e) {
            // Try ISO format as fallback
            try {
                return LocalDateTime.parse(dateStr.substring(0, 19));
            } catch (Exception ex) {
                return LocalDateTime.now();
            }
        }
    }
}

