async fn process_image(
    source_path: &Path,
    config: &Config
) -> Result<(), Box<dyn Error + Send + Sync>> {
    // Process in a separate blocking thread since image operations are CPU-bound
    let source_path = source_path.to_path_buf();
    let config = config.clone();

    task::spawn_blocking(move || -> Result<(), Box<dyn Error + Send + Sync>> {
        let file_name = source_path.file_name().ok_or("Invalid file name")?;
        let target_path = config.target_dir.join(file_name);

        // Open the image
        let img = image::open(&source_path)?;

        // Resize the image
        let resized = if config.maintain_aspect_ratio {
            let (width, height) = img.dimensions();
            let ratio = width as f32 / height as f32;

            let (new_width, new_height) = if ratio > 1.0 {
                // Width is larger
                let new_width = config.width;
                let new_height = (config.width as f32 / ratio) as u32;
                (new_width, new_height)
            } else {
                // Height is larger or equal
                let new_height = config.height;
                let new_width = (config.height as f32 * ratio) as u32;
                (new_width, new_height)
            };

            img.resize(new_width, new_height, image::imageops::FilterType::Lanczos3)
        } else {
            img.resize_exact(config.width, config.height, image::imageops::FilterType::Lanczos3)
        };

        // Save the resized image
        resized.save(&target_path)?;

        // Remove original file if save was successful
        fs::remove_file(&source_path)?;

        Ok(())
    }).await?
}

fn find_image_files(dir: &Path) -> io::Result<Vec<PathBuf>> {
    let mut image_files = Vec::new();

    if dir.is_dir() {
        for entry in fs::read_dir(dir)? {
            let entry = entry?;
            let path = entry.path();

            if path.is_dir() {
                let mut sub_dir_files = find_image_files(&path)?;
                image_files.append(&mut sub_dir_files);
            } else if let Some(extension) = path.extension() {
                let ext = extension.to_string_lossy().to_lowercase();
                if ext == "jpg" || ext == "jpeg" || ext == "png" {
                    image_files.push(path);
                }
            }
        }
    }

    Ok(image_files)
}
